# ui/other_settings.pyimport customtkinter as ctkfrom ui.i18n import tfrom ui.config_tab import create_label_with_helpfrom tkinter import messageboxfrom config_manager import load_config, save_configimport requestsfrom requests.auth import HTTPBasicAuthimport osfrom xml.etree import ElementTree as ETimport shutilimport timedef build_other_settings_tab(self):    self.other_settings_tab = self.tabview.add(t("其他设置"))    self.other_settings_tab.rowconfigure(0, weight=1)    self.other_settings_tab.columnconfigure(0, weight=1)    if "webdav_config" not in self.loaded_config:        self.loaded_config["webdav_config"] = {            "webdav_url": "",            "webdav_username": "",            "webdav_password": "",        }    self.webdav_url_var.set(self.loaded_config["webdav_config"].get("webdav_url", ""))    self.webdav_username_var.set(        self.loaded_config["webdav_config"].get("webdav_username", "")    )    self.webdav_password_var.set(        self.loaded_config["webdav_config"].get("webdav_password", "")    )    def save_webdav_settings():        self.loaded_config["webdav_config"]["webdav_url"] = (            self.webdav_url_var.get().strip()        )        self.loaded_config["webdav_config"]["webdav_username"] = (            self.webdav_username_var.get().strip()        )        self.loaded_config["webdav_config"]["webdav_password"] = (            self.webdav_password_var.get().strip()        )        save_config(self.loaded_config, self.config_file)    def test_webdav_connection(test=True):        try:            client = WebDAVClient(                self.webdav_url_var.get().strip(),                self.webdav_username_var.get().strip(),                self.webdav_password_var.get().strip(),            )            client.list_directory()            if not test:                save_webdav_settings()                return True            messagebox.showinfo(t("成功"), t("WebDAV 连接成功"))            save_webdav_settings()            return True        except Exception as e:            print(e)            messagebox.showerror(t("错误"), t("发生未知错误：{err}").format(err=e))            return False    def backup_to_webdav():        try:            target_dir = "AI_Novel_Generator"            client = WebDAVClient(                self.webdav_url_var.get().strip(),                self.webdav_username_var.get().strip(),                self.webdav_password_var.get().strip(),            )            if not client.ensure_directory_exists(target_dir):                client.create_directory(target_dir)            client.upload_file(self.config_file, f"{target_dir}/config.json")            messagebox.showinfo(t("成功"), t("配置备份成功"))        except Exception as e:            print(e)            messagebox.showerror(t("错误"), t("发生未知错误：{err}").format(err=e))            return False    def restore_from_webdav():        try:            target_dir = "AI_Novel_Generator"            client = WebDAVClient(                self.webdav_url_var.get().strip(),                self.webdav_username_var.get().strip(),                self.webdav_password_var.get().strip(),            )            client.download_file(f"{target_dir}/config.json", self.config_file)            self.loaded_config = load_config(self.config_file)            messagebox.showinfo(t("成功"), t("配置恢复成功"))        except Exception as e:            print(e)            messagebox.showerror(t("错误"), t("发生未知错误：{err}").format(err=e))            return False    dav_frame = ctk.CTkFrame(self.other_settings_tab)    dav_frame.pack(padx=20, pady=20, fill="x")    dav_title = ctk.CTkLabel(        dav_frame, text=t("WebDAV 设置"), font=("Microsoft YaHei", 16, "bold")    )    dav_title.pack(anchor="w", padx=5, pady=(0, 5))    dav_warp_frame = ctk.CTkFrame(        dav_frame, corner_radius=10, border_width=2, border_color="gray"    )    dav_warp_frame.pack(fill="x", padx=5)    dav_warp_frame.columnconfigure(1, weight=1)    create_label_with_help(        self,        parent=dav_warp_frame,        label_text=t("Webdav URL"),        tooltip_key="webdav_url",        row=0,        column=0,        font=("Microsoft YaHei", 12),        sticky="w",    )    dav_url_entry = ctk.CTkEntry(        dav_warp_frame, textvariable=self.webdav_url_var, font=("Microsoft YaHei", 12)    )    dav_url_entry.grid(row=0, column=1, padx=5, pady=5, sticky="w")    create_label_with_help(        self,        parent=dav_warp_frame,        label_text=t("Webdav 用户名"),        tooltip_key="webdav_username",        row=1,        column=0,        font=("Microsoft YaHei", 12),        sticky="w",    )    dav_username_entry = ctk.CTkEntry(        dav_warp_frame,        textvariable=self.webdav_username_var,        font=("Microsoft YaHei", 12),    )    dav_username_entry.grid(row=1, column=1, padx=5, pady=5, sticky="w")    create_label_with_help(        self,        parent=dav_warp_frame,        label_text=t("Webdav 密码"),        tooltip_key="webdav_password",        row=2,        column=0,        font=("Microsoft YaHei", 12),        sticky="w",    )    dav_password_entry = ctk.CTkEntry(        dav_warp_frame,        textvariable=self.webdav_password_var,        font=("Microsoft YaHei", 12),        show="*",    )    dav_password_entry.grid(row=2, column=1, padx=5, pady=5, sticky="w")    button_frame = ctk.CTkFrame(dav_warp_frame)    button_frame.grid(row=3, column=0, columnspan=2, padx=5, pady=10, sticky="w")    # 测试连接按钮    test_btn = ctk.CTkButton(        button_frame,        text=t("测试连接"),        font=("Microsoft YaHei", 12),        command=test_webdav_connection,    )    test_btn.pack(side="left", padx=5)    # 备份按钮    save_btn = ctk.CTkButton(        button_frame,        text=t("备份"),        font=("Microsoft YaHei", 12),        command=backup_to_webdav,    )    save_btn.pack(side="left", padx=5)    # 恢复按钮    reset_btn = ctk.CTkButton(        button_frame,        text=t("恢复"),        font=("Microsoft YaHei", 12),        command=restore_from_webdav,    )    reset_btn.pack(side="left", padx=5)class WebDAVClient:    def __init__(self, base_url, username, password):        """初始化朩ebDAV瀹㈡埛绔?"""        self.base_url = base_url.rstrip("/") + "/"        self.auth = HTTPBasicAuth(username, password)        self.headers = {"User-Agent": "Python WebDAV Client", "Accept": "*/*"}        # WebDAV鍛藉悕绌洪棿        self.ns = {"d": "DAV:"}    def _get_url(self, path):        """鑾峰彇瀹屾暣鐨勮祫婧怳RL"""        return self.base_url + path.lstrip("/")    def directory_exists(self, path):        """        妫€鏌ョ洰褰曟槸鍚﹀瓨鍦?        :param path: 目录路径        :return: 甯冨皵鍊硷紝琛ㄧず目录鏄惁瀛樺湪        """        url = self._get_url(path)        headers = self.headers.copy()        headers["Depth"] = "0"  # 鏌ュ綋鍓嶈祫婧?        try:            # 戦€丳ROPFIND璇锋眰妫€鏌ヨ祫婧愭槸鍚﹀瓨鍦?            response = requests.request(                "PROPFIND", url, headers=headers, auth=self.auth            )            # 207 Multi-Status琛ㄧず成功：岃鏄庤祫婧愬瓨鍦?            if response.status_code == 207:                # 瑙ｆ瀽XML鍝嶅簲：岀‘璁ゆ槸目录                root = ET.fromstring(response.content)                # 鏌ユ壘璧勬簮绫诲瀷灞炴€?                res_type = root.find(".//d:resourcetype", namespaces=self.ns)                # 濡傛灉鍖呭惈collection鍏冪礌：屽垯鏄洰褰?                if (                    res_type is not None                    and res_type.find("d:collection", namespaces=self.ns) is not None                ):                    return True            return False        except requests.exceptions.RequestException as e:            print(f"妫€鏌ョ洰褰曞瓨鍦ㄦ€ф椂鍑洪敊: {e}")            return False    def create_directory(self, path):        """        鍒涘缓杩滅▼目录        :param path: 瑕佸垱寤虹殑目录路径        :return: 鏄惁鍒涘缓成功        """        url = self._get_url(path)        try:            response = requests.request(                "MKCOL", url, auth=self.auth, headers=self.headers            )            response.raise_for_status()            print(f"目录鍒涘缓成功: {path}")            return True        except requests.exceptions.RequestException as e:            print(f"目录鍒涘缓澶辫触: {e}")            return False    def ensure_directory_exists(self, path):        """        纭繚目录瀛樺湪：屽鏋滀笉瀛樺湪鍒欏垱寤?        :param path: 目录路径        :return: 甯冨皵鍊硷紝琛ㄧず鏈€缁堢洰褰曟槸鍚﹀瓨鍦?        """        # 绉婚櫎鏈熬鐨勬枩鏉狅紙濡傛灉鏈夛級        path = path.rstrip("/")        # 濡傛灉目录已经瀛樺湪：岀洿鎺ヨ繑鍥濼rue        if self.directory_exists(path):            print(f"目录宸插瓨鍦? {path}")            return True        # 閫掑綊鍒涘缓鐖剁洰褰?        parent_dir = os.path.dirname(path)        if parent_dir and not self.directory_exists(parent_dir):            # 濡傛灉鐖剁洰褰曚笉瀛樺湪：屽垯鍏堝垱寤虹埗目录            if not self.ensure_directory_exists(parent_dir):                print(f"鍒涘缓鐖剁洰褰曞け璐? {parent_dir}")                return False        # 鍒涘缓褰撳墠目录        return self.create_directory(path)    def upload_file(self, local_path, remote_path):        """        涓婁紶文件鍒癢ebDAV鏈嶅姟鍣?        :param local_path: 鏈湴文件路径        :param remote_path: 杩滅▼文件路径        :return: 鏄惁涓婁紶成功        """        if not os.path.isfile(local_path):            print(f"鏈湴文件不存在? {local_path}")            return False        url = self._get_url(remote_path)        try:            with open(local_path, "rb") as f:                response = requests.put(                    url, data=f, auth=self.auth, headers=self.headers                )                response.raise_for_status()            print(f"文件涓婁紶成功: {local_path} -> {remote_path}")            return True        except requests.exceptions.RequestException as e:            print(f"文件涓婁紶澶辫触: {e}")            return False    def download_file(self, remote_path, local_path):        """        浠嶹ebDAV鏈嶅姟鍣ㄤ笅杞芥枃浠?        :param remote_path: 杩滅▼文件路径        :param local_path: 鏈湴保存路径        :return: 鏄惁涓嬭浇成功        """        url = self._get_url(remote_path)        local_path = os.path.join(            os.path.dirname(os.path.dirname(os.path.abspath(__file__))), local_path        )        self.backup(local_path)        try:            response = requests.get(                url, auth=self.auth, headers=self.headers, stream=True            )            response.raise_for_status()            # 鍒涘缓鏈湴目录：堝鏋滈渶瑕侊級            os.makedirs(os.path.dirname(local_path), exist_ok=True)            with open(local_path, "wb") as f:                for chunk in response.iter_content(chunk_size=8192):                    f.write(chunk)            print(f"文件涓嬭浇成功: {remote_path} -> {local_path}")            return True        except requests.exceptions.RequestException as e:            print(f"文件涓嬭浇澶辫触: {e}")            return False    def backup(self, local_path):        name_parts = os.path.basename(local_path).rsplit(".", 1)  # 垎鍓叉渶最后一涓偣        base_name = name_parts[0]        extension = name_parts[1]        timestamp = time.strftime("%Y%m%d%H%M%S")        if not os.path.exists(os.path.join(os.path.dirname(local_path), "backup")):            os.makedirs(os.path.join(os.path.dirname(local_path), "backup"))        backup_file_name = f"{base_name}_{timestamp}_bak.{extension}"        shutil.copy2(            os.path.basename(local_path),            os.path.join(os.path.dirname(local_path), "backup", backup_file_name),        )